    uint32_t batch = static_cast<uint32_t>(xShape.GetDim(0));
    uint32_t inputSize = static_cast<uint32_t>(xShape.GetDim(1));
    uint32_t hiddenSize = static_cast<uint32_t>(wShape.GetDim(0));  // weight shape: (hidden, input)

    // Scalar inputs as tensors of shape [1]
