    const float *pClampMin = reinterpret_cast<const float*>(context->GetInputTensor(4)->GetData());
    const float *pClampMax = reinterpret_cast<const float*>(context->GetInputTensor(5)->GetData());

    tiling.set_batch(batch);
    tiling.set_inputSize(inputSize);
    tiling.set_hiddenSize(hiddenSize);
    tiling.set_scaling(pScaling[0]);
    tiling.set_clampMin(pClampMin[0]);
    tiling.set_clampMax(pClampMax[0]);

    // Tiling over batches: each core processes a chunk of rows.
    // UB budget: we need to hold two rows of hiddenSize floats (one for matmul output, one for exp) plus some work.
    uint32_t rowBytes = hiddenSize * sizeof(float);
